const fs = require("fs");
const path = require("path");

const statusMap = {
  wantWatch: "想看",
  watching: "在看",
  watched: "看过",
};

function normalizeTags(item) {
  const tags = [];
  [item.type, item.area, item.tags]
    .flat()
    .filter(Boolean)
    .forEach((tag) => {
      String(tag)
        .split(/[,，/]/)
        .map((value) => value.trim())
        .filter(Boolean)
        .forEach((value) => tags.push(value));
    });
  return [...new Set(tags)];
}

function normalizeItem(item, status) {
  const id = item.id || item.media_id;
  return {
    ...item,
    title: item.title || item.name,
    origin_title: item.origin_title || item.original_title,
    status: item.status || status,
    rating: item.rating || item.score,
    episodes: item.episodes || item.totalCount,
    summary: item.summary || item.des || item.description,
    cover: item.cover,
    url: item.url || item.link || (id ? `https://www.bilibili.com/bangumi/media/md${id}/` : item.source_url),
    tags: normalizeTags(item),
  };
}

function readPluginBangumiData() {
  const file = path.join(hexo.source_dir, "_data", "bangumis.json");
  if (!fs.existsSync(file)) return [];

  try {
    const data = JSON.parse(fs.readFileSync(file, "utf8"));
    return Object.keys(statusMap).flatMap((key) => {
      const list = Array.isArray(data[key]) ? data[key] : [];
      return list.map((item) => normalizeItem(item, statusMap[key]));
    });
  } catch (error) {
    hexo.log.warn(`Failed to read bangumis.json: ${error.message}`);
    return [];
  }
}

hexo.extend.filter.register("before_generate", function () {
  const pluginItems = readPluginBangumiData();
  const pages = hexo.locals.get("pages").filter((page) => page.layout === "bangumi" || Array.isArray(page.bangumi));

  pages.forEach((page) => {
    const manualItems = Array.isArray(page.bangumi)
      ? page.bangumi.map((item) => normalizeItem(item, item.status))
      : [];
    page.bangumi_items = pluginItems.length ? pluginItems : manualItems;
  });
});
